{"path": "/home/admin/weather-web-app/tests/test.js", "content": "const http = require('http');
const { spawn } = require('child_process');
const path = require('path');
const assert = require('assert');

const TEST_PORT = 3001;
const SERVER_SCRIPT = path.join(__dirname, '..', 'server.js');
const BASE_URL = `http://localhost:${TEST_PORT}`;

let serverProcess = null;
let passed = 0;
let failed = 0;
const tests = [];

function test(name, fn) {
  tests.push({ name, fn });
}

function assertStatus(res, expected) {
  assert.strictEqual(
    res.statusCode,
    expected,
    `Expected status ${expected}, got ${res.statusCode}`
  );
}

function get(path) {
  return new Promise((resolve, reject) => {
    const req = http.get(`${BASE_URL}${path}`, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        resolve({ statusCode: res.statusCode, headers: res.headers, body: data });
      });
    });
    req.on('error', reject);
    req.setTimeout(10000, () => {
      req.destroy();
      reject(new Error(`Request to ${path} timed out`));
    });
  });
}

// --- Tests ---

test('Server starts and responds on port 3001', async () => {
  const res = await get('/health');
  assertStatus(res, 200);
});

test('GET /health returns 200 with { status: "ok" }', async () => {
  const res = await get('/health');
  assertStatus(res, 200);
  const body = JSON.parse(res.body);
  assert.deepStrictEqual(body, { status: 'ok' });
});

test('GET /api/weather?city=London returns 200 with valid weather fields', async () => {
  const res = await get('/api/weather?city=London');
  assertStatus(res, 200);
  const body = JSON.parse(res.body);
  assert.ok(typeof body.city === 'string' && body.city.length > 0, 'city should be a non-empty string');
  assert.ok(typeof body.country === 'string' && body.country.length > 0, 'country should be a non-empty string');
  assert.ok(typeof body.temperature === 'number', 'temperature should be a number');
  assert.ok(typeof body.feels_like === 'number', 'feels_like should be a number');
  assert.ok(typeof body.humidity === 'number', 'humidity should be a number');
  assert.ok(typeof body.wind_speed === 'number', 'wind_speed should be a number');
  assert.ok(typeof body.condition === 'string' && body.condition.length > 0, 'condition should be a non-empty string');
  assert.ok(typeof body.emoji === 'string' && body.emoji.length > 0, 'emoji should be a non-empty string');
  assert.ok(typeof body.weather_code === 'number', 'weather_code should be a number');
});

test('GET /api/weather?city= (empty) returns 400 with error message', async () => {
  const res = await get('/api/weather?city=');
  assertStatus(res, 400);
  const body = JSON.parse(res.body);
  assert.ok(body.error, 'response should have an error field');
  assert.strictEqual(body.error, 'City parameter is required');
});

test('GET /api/weather (no city param) returns 400 with error message', async () => {
  const res = await get('/api/weather');
  assertStatus(res, 400);
  const body = JSON.parse(res.body);
  assert.ok(body.error, 'response should have an error field');
  assert.strictEqual(body.error, 'City parameter is required');
});

test('GET /api/weather?city=ThisCityDoesNotExist returns 404 with error', async () => {
  const res = await get('/api/weather?city=ThisCityDoesNotExist');
  assertStatus(res, 404);
  const body = JSON.parse(res.body);
  assert.ok(body.error, 'response should have an error field');
  assert.ok(body.error.includes('not found'), 'error should indicate city not found');
});

test('GET / returns 200 with HTML content containing <title>Weather App</title>', async () => {
  const res = await get('/');
  assertStatus(res, 200);
  assert.ok(
    res.headers['content-type'] && res.headers['content-type'].includes('text/html'),
    'content-type should be text/html'
  );
  assert.ok(res.body.includes('<title>Weather App</title>'), 'HTML should contain <title>Weather App</title>');
});

test('GET /style.css returns 200 with CSS content', async () => {
  const res = await get('/style.css');
  assertStatus(res, 200);
  assert.ok(
    res.headers['content-type'] && res.headers['content-type'].includes('text/css'),
    'content-type should be text/css'
  );
  assert.ok(res.body.includes('body'), 'CSS should contain body styling');
});

test('GET /app.js returns 200 with JS content', async () => {
  const res = await get('/app.js');
  assertStatus(res, 200);
  assert.ok(
    res.headers['content-type'] && (res.headers['content-type'].includes('application/javascript') || res.headers['content-type'].includes('text/javascript')),
    'content-type should be application/javascript'
  );
  assert.ok(res.body.length > 0, 'JS file should not be empty');
});

// --- Runner ---

async function runTests() {
  console.log('Starting weather web app integration tests...\n');

  // Start the server
  console.log(`Starting server on port ${TEST_PORT}...`);
  serverProcess = spawn('node', [SERVER_SCRIPT], {
    env: { ...process.env, PORT: String(TEST_PORT) },
    stdio: ['pipe', 'pipe', 'pipe'],
  });

  // Wait for server to be ready
  let serverReady = false;
  await new Promise((resolve, reject) => {
    const timeout = setTimeout(() => {
      if (!serverReady) {
        reject(new Error('Server failed to start within 15 seconds'));
      }
    }, 15000);

    serverProcess.stdout.on('data', (data) => {
      const msg = data.toString();
      console.log('  [server]', msg.trim());
      if (msg.includes(`localhost:${TEST_PORT}`)) {
        serverReady = true;
        clearTimeout(timeout);
        resolve();
      }
    });

    serverProcess.stderr.on('data', (data) => {
      console.log('  [server:stderr]', data.toString().trim());
    });

    serverProcess.on('error', (err) => {
      clearTimeout(timeout);
      reject(err);
    });

    serverProcess.on('exit', (code) => {
      clearTimeout(timeout);
      if (!serverReady) {
        reject(new Error(`Server exited with code ${code} before becoming ready`));
      }
    });
  });

  console.log('Server is ready.\n');

  // Run tests sequentially
  for (const { name, fn } of tests) {
    try {
      await fn();
      console.log(`  ✓ PASS: ${name}`);
      passed++;
    } catch (err) {
      console.log(`  ✗ FAIL: ${name}`);
      console.log(`    ${err.message}`);
      failed++;
    }
  }

  // Cleanup: kill server
  console.log('\nShutting down server...');
  if (serverProcess) {
    serverProcess.kill('SIGTERM');
    // Wait for clean exit
    await new Promise((resolve) => {
      const killTimeout = setTimeout(() => {
        serverProcess.kill('SIGKILL');
        resolve();
      }, 5000);
      serverProcess.on('exit', () => {
        clearTimeout(killTimeout);
        resolve();
      });
    });
  }

  // Summary
  const total = passed + failed;
  console.log(`\n╔══════════════════════════════════════╗`);
  console.log(`║  Results: ${passed}/${total} passed, ${failed} failed  ║`);
  console.log(`╚══════════════════════════════════════╝`);

  process.exit(failed > 0 ? 1 : 0);
}

runTests().catch((err) => {
  console.error('Fatal error:', err.message);
  if (serverProcess) {
    serverProcess.kill('SIGKILL');
  }
  process.exit(1);
});
"}
